// ─── Build combined seeds ─────────────────────────────────────────────────────

function buildSeed(entry, region) {
  return {
    name: entry.name,
    cik: entry.cik ?? null,
    ticker: entry.ticker ?? null,
    region,
    sector: entry.sector ?? "unknown",
    lei: entry.lei ?? null,
    wikidata_id: entry.wikidata_id ?? null,
    us_subsidiary_ciks: [],
  };
}

const seeds = [
  ...US_SEEDS.map((e) => buildSeed(e, "US")),
  ...US_SEEDS_2.map((e) => buildSeed(e, "US")),
  ...JP_SEEDS.map((e) => buildSeed(e, "JP")),
  ...JP_SEEDS_2.map((e) => buildSeed(e, "JP")),
  ...EU_SEEDS.map((e) => buildSeed(e, "EU")),
  ...EU_SEEDS_2.map((e) => buildSeed(e, "EU")),
];

// Deduplicate by name
const seen = new Set();
const deduped = seeds.filter((s) => {
  const key = s.name.toLowerCase();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Validation
const valid = deduped.filter(
  (s) => s.name && s.region && (s.cik || s.lei || s.wikidata_id)
);
const invalid = deduped.filter(
  (s) => !(s.cik || s.lei || s.wikidata_id)
);
if (invalid.length > 0) {
  console.warn(`WARNING: ${invalid.length} entries missing all identifiers:`);
  invalid.forEach((s) => console.warn(`  - ${s.name}`));
}

writeFileSync(OUTPUT_PATH, JSON.stringify(valid, null, 2), "utf-8");
console.log(`Generated ${valid.length} entity seeds → ${OUTPUT_PATH}`);
console.log(`  US: ${valid.filter((s) => s.region === "US").length}`);
console.log(`  JP: ${valid.filter((s) => s.region === "JP").length}`);
console.log(`  EU: ${valid.filter((s) => s.region === "EU").length}`);
